# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    static func handleUniversalLink(_ url: URL) -> Bool {
        guard url.host == "myapp.com" else { return false }
        
        if url.path == "/reset-password" {
            if let token = url.queryParameters["token"] {
                navigateToPasswordResetScreen(token: token)
                return true
            }
        }
        return false
    }
    
    private static func navigateToPasswordResetScreen(token: String) {
        DispatchQueue.main.async {
            if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
               let window = windowScene.windows.first {
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                if let resetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
                    resetVC.resetToken = token
                    let navController = UINavigationController(rootViewController: resetVC)
                    window.rootViewController?.present(navController, animated: true)
                }
            }
        }
    }
}

extension URL {
    var queryParameters: [String: String] {
        guard let components = URLComponents(url: self, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return [:]
        }
        
        var parameters: [String: String] = [:]
        for item in queryItems {
            parameters[item.name] = item.value
        }
        return parameters
    }
}